func (fx *FeaturestoreServiceFeatureTestSuiteConfig) testUpdate(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		msg := fx.Update(parent)
		msg.Name = ""
		_, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
			Feature: msg,
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument if provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		msg := fx.Update(parent)
		msg.Name = "invalid resource name"
		_, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
			Feature: msg,
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// The updated resource should be persisted and reachable with Get.
	t.Run("persisted", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		updateResp, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
			Feature: created,
		}))
		assert.NilError(t, err)
		assert.Check(t, updateResp != nil)
		updated := updateResp.Msg
		assert.NilError(t, err)
		getResp, err := fx.Service().GetFeature(fx.Context(), connect.NewRequest(&aiplatformpb.GetFeatureRequest{
			Name: updated.Name,
		}))
		assert.NilError(t, err)
		assert.Check(t, getResp != nil)
		persisted := getResp.Msg
		assert.NilError(t, err)
		assert.DeepEqual(t, updated, persisted, protocmp.Transform())
	})

	// Method should fail with Aborted if the supplied etag doesnt match the current etag value.
	t.Run("etag mismatch", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		msg := fx.Update(parent)
		msg.Name = created.Name
		msg.Etag = `"99999"`
		_, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
			Feature: msg,
		}))
		assert.Equal(t, connect.CodeAborted, connect.CodeOf(err), err)
	})

	// Field etag should have a new value when the resource is successfully updated.
	t.Run("etag updated", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		msg := fx.Update(parent)
		msg.Name = created.Name
		msg.Etag = created.Etag
		updateResp, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
			Feature: msg,
		}))
		assert.NilError(t, err)
		assert.Check(t, updateResp != nil)
		updated := updateResp.Msg
		assert.NilError(t, err)
		assert.Check(t, updated.Etag != created.Etag)
	})

	{
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		// Method should fail with NotFound if the resource does not exist.
		t.Run("not found", func(t *testing.T) {
			fx.maybeSkip(t)
			msg := fx.Update(parent)
			msg.Name = created.Name + "notfound"
			_, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
				Feature: msg,
			}))
			assert.Equal(t, connect.CodeNotFound, connect.CodeOf(err), err)
		})

		// The method should fail with InvalidArgument if the update_mask is invalid.
		t.Run("invalid update mask", func(t *testing.T) {
			fx.maybeSkip(t)
			_, err := fx.Service().UpdateFeature(fx.Context(), connect.NewRequest(&aiplatformpb.UpdateFeatureRequest{
				Feature: created,
				UpdateMask: &fieldmaskpb.FieldMask{
					Paths: []string{
						"invalid_field_xyz",
					},
				},
			}))
			assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
		})

	}
}

func (fx *FeaturestoreServiceFeatureTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
			Parent: "invalid resource name",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
			Parent:    parent,
			PageToken: "invalid page token",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
			Parent:   parent,
			PageSize: -10,
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	{
		const resourcesCount = 15
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.Feature, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
				Parent:   parent,
				PageSize: 999,
			}))
			assert.NilError(t, err)
			assert.Check(t, listResp != nil)
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.Features,
				cmpopts.SortSlices(func(a, b *aiplatformpb.Feature) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
				Parent:   parent,
				PageSize: resourcesCount,
			}))
			assert.NilError(t, err)
			assert.Check(t, listResp != nil)
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Equal(t, "", response.NextPageToken)
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
				Parent:   parent,
				PageSize: resourcesCount - 1,
			}))
			assert.NilError(t, err)
			assert.Check(t, listResp != nil)
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Check(t, response.NextPageToken != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.Feature, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
					Parent:    parent,
					PageSize:  1,
					PageToken: nextPageToken,
				}))
				assert.NilError(t, err)
				assert.Check(t, listResp != nil)
				response := listResp.Msg
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.Features))
				msgs = append(msgs, response.Features...)
				nextPageToken = response.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.Feature) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// Method should not return deleted resources.
		t.Run("deleted", func(t *testing.T) {
			fx.maybeSkip(t)
			const deleteCount = 5
			for i := 0; i < deleteCount; i++ {
				_, err := fx.Service().DeleteFeature(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteFeatureRequest{
					Name: parentMsgs[i].Name,
				}))
				assert.NilError(t, err)
			}
			listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
				Parent:   parent,
				PageSize: 9999,
			}))
			assert.NilError(t, err)
			assert.Check(t, listResp != nil)
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs[deleteCount:],
				response.Features,
				cmpopts.SortSlices(func(a, b *aiplatformpb.Feature) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
	{
		const resourcesCount = 101
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.Feature, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// Listing resource with page size zero should eventually return all resources.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.Feature, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListFeatures(fx.Context(), connect.NewRequest(&aiplatformpb.ListFeaturesRequest{
					Parent:    parent,
					PageSize:  0,
					PageToken: nextPageToken,
				}))
				assert.NilError(t, err)
				assert.Check(t, listResp != nil)
				page := listResp.Msg
				assert.NilError(t, err)
				msgs = append(msgs, page.Features...)
				nextPageToken = page.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.Feature) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
}

